/**
 * Filter the given array of files, removing any empty values.
 *
 * @param  mixed  $files
 * @return mixed
 */
protected function filterFiles($files)
{
    if (! $files) {
        return;
    }

    foreach ($files as $key => $file) {
        if (is_array($file)) {
            $files[$key] = $this->filterFiles($files[$key]);
        }

        if (empty($files[$key])) {
            unset($files[$key]);
        }
    }

    return $files;
